        public LocationRepository(string connectionString)
        {
            _connectionString = connectionString;        }

        public Task<DatabaseResult<List<Element>>> GetLocationsAsync(string []componentId)
        {
            return Task.Run(() =>
            {
                try
                {
                    var locations = Element.GetElementsByType(componentId);
                    locations = locations.Where(loc => loc.ContainerID != null && zakres.Contains($"'{loc.ContainerID}'")).ToList();
                    
                    return DatabaseResult<List<Element>>.Success(locations);
                }
                catch (Exception ex)
                {                    
                    return DatabaseResult<List<Element>>.Failure($"Error getting locations: {ex.Message}", ex);
                }
            });
        }

        public Task<DatabaseResult<List<Element>>> GetLocationsTHTAsync(string []componentId)
        {
            return Task.Run(() =>
            {
                try
                {
                    var locations = Element.GetElementsByType(componentId);
                    locations = locations.Where(loc => loc.ContainerID != null).ToList();
                    
                    return DatabaseResult<List<Element>>.Success(locations);
                }
                catch (Exception ex)
                {                    
                    return DatabaseResult<List<Element>>.Failure($"Error getting locations: {ex.Message}", ex);
                }
            });
        }
